            <ThumbColumn
              scrollRef={scrollRef}
              pdfPath={pathA}
              count={countA}
              itemHeight={itemHeight}
              paddingStart={offsetA}
              left={0}
              colWidth={colWidth}
              thumbHeight={thumbHeight}
              onResize={onResize}
              selectedPage={selectedPageA}
              onSelectPage={onSelectPageA}
              pageLabel={pageLabelA}
            />
            <ThumbColumn
              scrollRef={scrollRef}
              pdfPath={pathB}
              count={countB}
              itemHeight={itemHeight}
              paddingStart={offsetB}
              left={colWidth}
              colWidth={colWidth}
              thumbHeight={thumbHeight}
              onResize={onResize}
              selectedPage={selectedPageB}
              onSelectPage={onSelectPageB}
              pageLabel={pageLabelB}
            />
          </div>
        </div>
      </Box>

      {/* Resize drag handle */}
      <div
        onMouseDown={startDrag}
        style={{
          width: DRAG_HANDLE_WIDTH,
          height: '100%',
          cursor: 'col-resize',
          flexShrink: 0,
          background: 'var(--mantine-color-gray-3)',
        }}
      />
    </Box>
  )
}

interface ThumbColumnProps {
  scrollRef: React.RefObject<HTMLDivElement | null>
  pdfPath: string | null
  count: number
  itemHeight: number
  paddingStart: number
  left: number
  colWidth: number
  thumbHeight: number
  onResize: number
  selectedPage: number
  onSelectPage: (page: number) => void
  pageLabel?: (index: number) => number
}

function ThumbColumn({
  scrollRef, pdfPath, count, itemHeight, paddingStart,
  left, colWidth, thumbHeight,
  onResize, selectedPage, onSelectPage, pageLabel,
}: ThumbColumnProps) {
  const thumbWidth = colWidth - ITEM_PADDING * 2
  const { getSrc, isLoading, load, invalidate } = usePageLoader(pdfPath ?? '', thumbWidth)

  const virtualizer = useVirtualizer({
    count,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => itemHeight,
    overscan: 3,
    paddingStart,
  })

  useEffect(() => {
    virtualizer.measure()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [itemHeight])

  useEffect(() => {
    for (const item of virtualizer.getVirtualItems()) load(item.index + 1)
  })

  useEffect(() => {
    if (count > 0) virtualizer.scrollToIndex(selectedPage - 1, { align: 'auto' })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedPage])

  useEffect(() => {
    if (onResize > 0) invalidate()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [onResize])

  return (
    <div style={{ position: 'absolute', left, top: 0, width: colWidth, height: '100%' }}>
      {virtualizer.getVirtualItems().map(item => {
        const page = item.index + 1
        const src = getSrc(page)
        const isSelected = page === selectedPage
        return (
          <div
            key={item.key}
            onClick={() => onSelectPage(page)}
            style={{
              position: 'absolute',
              top: item.start,
              left: 0,
              width: '100%',
              height: item.size,
              padding: ITEM_PADDING,
              paddingBottom: 0,
              boxSizing: 'border-box',
              cursor: 'pointer',
            }}
          >
            <div style={{
              border: `2px solid ${isSelected ? 'var(--mantine-color-blue-5)' : 'transparent'}`,
              borderRadius: 4,
              overflow: 'hidden',
              background: 'var(--mantine-color-gray-1)',
            }}>
              {src ? (
                <img src={src} alt={`page ${page}`} style={{ width: '100%', display: 'block' }} draggable={false} />
              ) : (
                <div style={{ width: '100%', height: thumbHeight, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  {isLoading(page) && <Loader size="xs" />}
                </div>
              )}
            </div>
            <div style={{ textAlign: 'center', fontSize: 11, color: 'var(--mantine-color-gray-7)', height: LABEL_HEIGHT, lineHeight: `${LABEL_HEIGHT}px` }}>
              {pageLabel ? pageLabel(item.index) : page}
            </div>
          </div>
        )
      })}
    </div>
  )
}

function ColumnHeader({
  label, path, width, onChoose, borderRight,
}: {
  label: string
  path: string | null
  width: number
  onChoose: () => void
  borderRight?: boolean
}) {
  return (
    <Box
      style={{
        width,
        flexShrink: 0,
        padding: '6px 8px',
        borderRight: borderRight ? '1px solid var(--mantine-color-gray-3)' : undefined,
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        gap: 2,
      }}
    >
      <Group justify="space-between" gap={4} wrap="nowrap">
        <Text size="xs" c="dimmed">{label}</Text>
        <Button size="xs" variant="default" onClick={onChoose}>Choose…</Button>
      </Group>
      <Text
        size="xs"
        style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
        title={path ?? undefined}
      >
        {path ? basename(path) : '—'}
      </Text>
    </Box>
  )
}

