14	// countOther: page count of the other panel.
15	function makePageNumberLabel(isFirst: boolean, countOther: number) {
16	  const minCount = countOther  // interleaved section length = min(count, countOther), but we only know countOther here
17	  return (index: number) => {
18	    const n = index + 1  // 1-based
19	    if (n <= minCount) {
20	      return isFirst ? 2 * n - 1 : 2 * n
21	    }
22	    // extra pages appended after interleave
23	    return 2 * minCount + (n - minCount)
24	  }
25	}
26	
27	function itemHeight(panelWidth: number) {
28	  const thumbWidth = panelWidth - ITEM_PADDING * 2
