48	  const [merging, setMerging] = useState(false)
49	  const refA = useRef<ThumbnailPanelHandle>(null)
50	  const refB = useRef<ThumbnailPanelHandle>(null)
51	  const syncing = useRef(false)
52	
53	  const handleScrollA = (top: number) => {
54	    if (syncing.current) return
55	    syncing.current = true
56	    refB.current?.scrollTo(top)
57	    syncing.current = false
58	  }
59	
60	  const handleScrollB = (top: number) => {
61	    if (syncing.current) return
